      color: #333;
      margin-top: 0;
    }}
    .slider-container {{
      text-align: center;
      margin: 15px 0;
    }}
    .slider-container label {{
      font-weight: bold;
      margin-right: 10px;
    }}
    .slider-container input[type="range"] {{
      vertical-align: middle;
      width: 300px;
    }}
    .slider-container .year-value {{
      display: inline-block;
      width: 50px;
      font-weight: bold;
      font-size: 1.1em;
    }}
    .chart-wrapper {{
      text-align: center;
    }}
    .chart-wrapper svg {{
      max-width: 100%;
      height: auto;
    }}
  </style>
  <script src="https://cdn.jsdelivr.net/npm/vega@6"></script>
  <script src="https://cdn.jsdelivr.net/npm/vega-lite@6.4.1"></script>
  <script src="https://cdn.jsdelivr.net/npm/vega-embed@7"></script>
</head>
<body>
  <div class="container">
    <h1>World Population Bubble Map</h1>
    <div class="slider-container">
      <label for="year-slider">Year:</label>
      <input type="range" id="year-slider" name="Year" min="1955" max="2005" step="5" value="1955">
      <span class="year-value" id="year-display">1955</span>
    </div>
    <div class="chart-wrapper" id="chart-container">
      {svg_string}
    </div>
  </div>
  <script>
    (function() {{
      var spec = {spec_json};
      var slider = document.getElementById('year-slider');
      var display = document.getElementById('year-display');
      var container = document.getElementById('chart-container');

      // Embed the Vega-Lite spec (replaces the static SVG with interactive version)
      var view;
      vegaEmbed('#chart-container', spec, {{ mode: 'vega-lite', actions: false }})
        .then(function(result) {{
          view = result.view;

          // Sync the slider with Vega's internal signal
          slider.addEventListener('input', function() {{
            var year = +this.value;
            display.textContent = year;
            if (view) {{
              view.signal('Year', year).run();
            }}
          }});

          // Listen for Vega signal changes to keep slider in sync
          view.addSignalListener('Year', function(name, value) {{
            slider.value = value;
            display.textContent = value;
          }});
        }})
        .catch(function(err) {{
          console.error('Vega-Embed error:', err);
          // Keep the static SVG as fallback
        }});
    }})();
  </script>
</body>
</html>"""

    with open("chart.html", "w") as f:
        f.write(html)

    print("Saved chart.html and spec.json")


