import json

with open('/home/user/myproject/spec.json', 'r') as f:
    spec = json.load(f)

errors = []

# Check top-level structure
if 'layer' not in spec:
    errors.append('Missing top-level layer')
else:
    layers = spec['layer']
    marks = []
    for layer in layers:
        mark = layer.get('mark', {})
        if isinstance(mark, dict):
            marks.append(mark.get('type'))
        elif isinstance(mark, str):
            marks.append(mark)

    if 'geoshape' not in marks:
        errors.append(f'No geoshape mark found. Marks: {marks}')
    if 'circle' not in marks:
        errors.append(f'No circle mark found. Marks: {marks}')
    print(f'Marks found: {marks}')

# Check projection
proj = spec.get('projection', {})
if proj.get('type') != 'naturalEarth1':
    errors.append(f'Projection type is not naturalEarth1: {proj.get(\"type\")}')

# Check params
params = spec.get('params', [])
range_params = [p for p in params if isinstance(p.get('bind'), dict) and p['bind'].get('input') == 'range']
if not range_params:
    errors.append('No binding_range param found')
else:
    bind = range_params[0]['bind']
    if bind.get('min') != 1955:
        errors.append(f'Slider min is not 1955: {bind.get(\"min\")}')
    if bind.get('max') != 2005:
        errors.append(f'Slider max is not 2005: {bind.get(\"max\")}')
    if bind.get('step') != 5:
        errors.append(f'Slider step is not 5: {bind.get(\"step\")}')
    print(f'Binding range: min={bind.get(\"min\")}, max={bind.get(\"max\")}, step={bind.get(\"step\")}')

# Check transform_filter references year param
bubble_layer = spec['layer'][1]
transforms = bubble_layer.get('transform', [])
filter_transforms = [t for t in transforms if 'filter' in t]
year_param_name = range_params[0]['name'] if range_params else None

if filter_transforms:
    filter_expr = filter_transforms[0]['filter']
    print(f'Filter expression: {filter_expr}')
    if year_param_name and year_param_name not in filter_expr:
        errors.append(f'Filter does not reference param {year_param_name}')
    if 'year' not in filter_expr:
        errors.append('Filter does not reference field year')
else:
    errors.append('No transform_filter found')

# Check size scale domain
enc = bubble_layer.get('encoding', {})
size = enc.get('size', {})
scale = size.get('scale', {})
domain = scale.get('domain', [])
if isinstance(domain, list) and len(domain) == 2:
    print(f'Size scale domain: {domain}')
    if domain[0] != 0:
        errors.append(f'Size domain does not start at 0: {domain}')
else:
    errors.append(f'Size scale domain is not a 2-element list: {domain}')

if errors:
    print('\\nERRORS:')
    for e in errors:
        print(f'  - {e}')
else:
    print('\\nAll spec.json checks PASSED!')
